{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-heater-multi-action-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流股 feed-1 缺少流量规格，以及已选中的加热器 heater-1 在出口温控模式下缺少目标温度这两类问题，生成局部候选提案。",
      "issues": [
        {
          "title": "进料流股缺少流量规格",
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "加热器出口温控目标缺失",
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-1 补充流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-1"
          },
          "rationale": "诊断直接指出 Cold Feed 缺少流量规格。当前仅有温度和压力，适合先补充最小可审查的流量占位，而不假定具体数值。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "value_type": "number",
                "unit_family": "flow_rate"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 heater-1 补充出口目标温度占位",
          "target": {
            "type": "unit",
            "id": "heater-1"
          },
          "rationale": "诊断表明 Feed Heater 已设置为 outlet_temperature 控制模式，但缺少对应目标温度参数。当前证据不足以推断具体目标值，适合仅添加参数占位。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target_c": {
                "required": true,
                "value_type": "number",
                "unit": "C"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.96,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-1",
        "flowdoc-unit-1"
      ]
    }
  ]
}
